import 'package:flutter_test/flutter_test.dart'; import 'package:googlepro/features/device_management/model/device_model_local.dart'; void main() { group('DeviceModelLocal', () { test('fromJson/toJson round trip', () { final d = DeviceModelLocal(deviceId: 'd1', deviceName: 'Pixel', ownerUserId: 'uid1', isOnline: true, batteryLevel: 75); final j = d.toJson(); final r = DeviceModelLocal.fromJson(j); expect(r.deviceId, d.deviceId); expect(r.deviceName, d.deviceName); expect(r.isOnline, d.isOnline); expect(r.batteryLevel, d.batteryLevel); }); test('copyWith only changes specified fields', () { final d = DeviceModelLocal(deviceId: 'd1', deviceName: 'Old', ownerUserId: 'uid1'); final d2 = d.copyWith(deviceName: 'New', isOnline: true); expect(d2.deviceName, 'New'); expect(d2.isOnline, true); expect(d2.deviceId, d.deviceId); }); }); }